SELECT COUNT(*)
FROM STUDENT_PARENT
WHERE STUDENT_ID = #{studentId}
AND PARENT_ID = #{parentId}
AND LINK_STATUS = 1

SELECT MAX(LINK_STATUS)
FROM STUDENT_PARENT
WHERE STUDENT_ID = #{studentId}
AND PARENT_ID = #{parentId}

mapper.update:
UPDATE STUDENT_PARENT
SET LINK_STATUS = 0,
UNLINKED_AT = SYSDATE
WHERE PARENT_ID = #{parentId}
AND STUDENT_ID = #{studentId}
AND LINK_STATUS = 1

UPDATE PARENT
SET PARENT_NAME = #{name},
BIRTH = #{birth},
INTRO = #{intro},
PROFILE_IMAGE = #{profile_image}
WHERE PARENT_ID = #{member_id}

UPDATE TEACHER
SET TEACHER_NAME = #{name},
BIRTH = #{birth},
INTRO = #{intro},
PROFILE_IMAGE = #{profile_image}
WHERE TEACHER_ID = #{member_id}

UPDATE STUDENT
SET PHONE = #{phone}
WHERE STUDENT_ID = #{member_id}

UPDATE PARENT
SET PHONE = #{phone}
WHERE PARENT_ID = #{member_id}

UPDATE TEACHER
SET PHONE = #{phone}
WHERE TEACHER_ID = #{member_id}
